VALUES
  ('disabled-57f41407-moex-00616', 'disabled-57f41407', 'disabled-57f41407-moex-110-01c5eaab', 'sub-disabled-57f41407-04', NULL, 'single_choice', '下列選項中的敘述，何者錯誤？', '["「三教九流」中的三教是指儒教、佛教、道教", "「三姑六婆」是指親屬之間的正常稱謂，後用以比喻人多嘴雜", "「六甲」相傳是上天創造萬物的日子，故稱女子懷孕為「身懷六甲」", "「三頭六臂」是指某一種天神的長相，後用以比喻人神通廣大，能力很強"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00617', 'disabled-57f41407', 'disabled-57f41407-moex-110-01c5eaab', 'sub-disabled-57f41407-04', NULL, 'single_choice', '下列選項與孔子「學而不厭」之精神，最接近的是：', '["學而不思則罔，思而不學則殆", "發憤忘食，樂以忘憂，不知老之將至云爾", "吾嘗終日不食，終夜不寢，以思；無益，不如學也", "不憤不啟，不悱不發，舉一隅不以三隅反，則不復也"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00618', 'disabled-57f41407', 'disabled-57f41407-moex-110-01c5eaab', 'sub-disabled-57f41407-04', NULL, 'single_choice', '世皆稱孟嘗君能得士，士以故歸之，而卒賴其力以脫於虎豹之秦。嗟乎！ 孟嘗君特雞鳴狗盜之雄耳，豈足以言得士！不然，擅齊之強，得一士焉， 宜可以南面而制秦，尚何取雞鳴狗盜之力哉？夫雞鳴狗盜之出其門，此士 之所以不至也。（王安石〈讀孟嘗君傳〉）本文意旨為何？', '["剖析孟嘗君能得士的原因", "反駁孟嘗君能得士的說法", "讚賞孟嘗君能得士的手段", "批判孟嘗君能得士的局勢"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00619', 'disabled-57f41407', 'disabled-57f41407-moex-110-01c5eaab', 'sub-disabled-57f41407-04', NULL, 'single_choice', '承上題，依據上文，下列形容孟嘗君與其所得之士的關係，何者較為恰當？', '["物以類聚", "相得益彰", "各懷鬼胎", "陽奉陰違"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00620', 'disabled-57f41407', 'disabled-57f41407-moex-110-01c5eaab', 'sub-disabled-57f41407-04', NULL, 'single_choice', '海之魚，有烏賊其名者。呴水，而水鳥戲於岸間。懼物之窺己也，則呴水 以蔽物。海鳥疑而視之，知其魚也而攫之。嗚呼！徒知自蔽以求全，不知 滅迹以杜疑，為識者之所窺，哀哉！（蘇軾〈二魚說〉）依據文中敘述， 烏賊呴水之目的為何？', '["捕捉食物", "炫耀技能", "遊戲自娛", "自我保護"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00621', 'disabled-57f41407', 'disabled-57f41407-moex-110-01c5eaab', 'sub-disabled-57f41407-04', NULL, 'single_choice', '承上題，下列選項中的成語，何者最適合形容文中之烏賊？', '["掩耳盜鈴", "欲蓋彌彰", "自欺欺人", "束手就擒"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00622', 'disabled-57f41407', 'disabled-57f41407-moex-110-01c5eaab', 'sub-disabled-57f41407-04', NULL, 'single_choice', '弈秋，通國之善弈者也。使弈秋誨二人弈，其一人專心致志，惟弈秋之為 聽。一人雖聽之，一心以為有鴻鵠將至，思援弓繳而射之，雖與之俱學， 弗若之矣。（《孟子．告子上》）依據上文文意，學習態度應該是：', '["足不出戶", "目不窺園", "耳不暇聽", "衣不解帶"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00623', 'disabled-57f41407', 'disabled-57f41407-moex-110-01c5eaab', 'sub-disabled-57f41407-04', NULL, 'single_choice', '《禮記．學記》：「三年視敬業樂群」下列何者與本文的意旨最接近？', '["博學篤志，切問近思", "己所不欲，勿施於人", "以文會友，以友輔仁", "知類通達，強立不反"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00624', 'disabled-57f41407', 'disabled-57f41407-moex-110-01c5eaab', 'sub-disabled-57f41407-04', NULL, 'single_choice', '荀子曰：「君子居必擇鄉，遊必就士，所以防邪僻而近中正也。」下列何 者與本文的意旨最相近？', '["螣蛇無足而飛，梧鼠五技而窮", "里仁為美，擇不處仁，焉得智", "假輿馬者，非利足也，而致千里", "強自取柱，柔自取束；邪穢在身，怨之所構"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00625', 'disabled-57f41407', 'disabled-57f41407-moex-110-01c5eaab', 'sub-disabled-57f41407-04', NULL, 'single_choice', '善學者，師逸而功倍，又從而庸之；不善學者，師勤而功半，又從而怨之。 （《禮記．學記》）關於本文的解讀，最適合的選項是：', '["學生能掌握學習方法，老師便教得輕鬆", "學習成果的好壞，取決於教師的勤與逸", "有效的教學方法，能快速提升學習成果", "不懂得學習的人，總是抱怨老師留一手"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL)
